#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        double totalLoss = 0;
        for (int i = 0; i < N; i++) {
            double price, quantity, discount;
            scanf("%lf %lf %lf", &price, &quantity, &discount);
            double increasedPrice = price * (1 + discount / 100);
            double finalPrice = increasedPrice * (1 - discount / 100);
            totalLoss += (price - finalPrice) * quantity;
        }
        printf("%.6f\n", totalLoss);
    }
    return 0;
}

