import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            double totalLoss = 0;
            for (int i = 0; i < N; i++) {
                double price = sc.nextDouble();
                double quantity = sc.nextDouble();
                double discount = sc.nextDouble();
                double increasedPrice = price * (1 + discount / 100);
                double finalPrice = increasedPrice * (1 - discount / 100);
                totalLoss += (price - finalPrice) * quantity;
            }
            System.out.printf("%.6f\n", totalLoss);
        }
    }
}

