const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const N = parseInt(readline());
    let totalLoss = 0;
    for (let j = 0; j < N; j++) {
        const [price, quantity, discount] = readline().split(' ').map(Number);
        const increasedPrice = price * (1 + discount / 100);
        const finalPrice = increasedPrice * (1 - discount / 100);
        totalLoss += (price - finalPrice) * quantity;
    }
    console.log(totalLoss.toFixed(6));
}
